import React from 'react';
import { useParams } from 'react-router-dom';
import { QuizApiClient } from '@/infrastructure/quiz/QuizApiClient';

export default function PublicQuizPlayPage() {
  const { code } = useParams();
  const api = React.useMemo(() => new QuizApiClient(), []);
  const [loading, setLoading] = React.useState(true);
  const [quiz, setQuiz] = React.useState(null);
  const [error, setError] = React.useState('');
  const [playerName, setPlayerName] = React.useState('');
  const [answers, setAnswers] = React.useState({});
  const [currentIndex, setCurrentIndex] = React.useState(0);
  const [result, setResult] = React.useState(null);
  const [timeLeftSec, setTimeLeftSec] = React.useState(null);

  const questions = quiz?.questions || [];
  const total = questions.length;
  const current = total > 0 ? questions[currentIndex] : null;

  React.useEffect(() => {
    let mounted = true;
    if (!code) return undefined;
    setLoading(true);
    api
      .getPublicQuizByCode(code)
      .then((data) => {
        if (!mounted) return;
        setQuiz(data);
      })
      .catch((e) => setError(e.message || 'Không tải được bài test.'))
      .finally(() => setLoading(false));
    return () => {
      mounted = false;
    };
  }, [api, code]);

  React.useEffect(() => {
    if (!quiz || result) return undefined;
    const min = Number(quiz.time_limit_minutes || 0);
    if (min <= 0) {
      setTimeLeftSec(null);
      return undefined;
    }
    setTimeLeftSec(min * 60);
    const t = setInterval(() => {
      setTimeLeftSec((prev) => {
        if (prev == null || prev <= 1) return 0;
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(t);
  }, [quiz?.id, result]);

  const submit = async (event) => {
    event?.preventDefault();
    if (!code) return;
    try {
      const data = await api.submitPublicQuizByCode(code, {
        player_name: playerName || 'Khách',
        answers,
        time_taken: 0,
      });
      setResult(data);
    } catch (e) {
      setError(e.message || 'Nộp bài thất bại.');
    }
  };

  const fmtTime = (sec) => {
    const m = Math.floor(sec / 60);
    const s = sec % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  if (loading) return <main className="mx-auto max-w-4xl p-8">Đang tải bài test...</main>;
  if (error && !quiz) return <main className="mx-auto max-w-4xl p-8 text-rose-700">{error}</main>;
  if (!quiz) return null;

  const qr = result?.question_results || [];

  return (
    <main className="mx-auto max-w-3xl space-y-6 p-4 md:p-8">
      <section className="rounded-2xl bg-white p-6 shadow-sm">
        <h1 className="font-headline text-3xl font-extrabold">{quiz.title}</h1>
        <p className="mt-2 text-slate-600">{quiz.description || 'Bài test chia sẻ công khai'}</p>
        <div className="mt-3 flex flex-wrap items-center gap-3 text-xs text-slate-400">
          <span>Code: {quiz.share_code}</span>
          <span>|</span>
          <span>Đạt: {quiz.pass_score}%</span>
          {quiz.time_limit_minutes ? (
            <>
              <span>|</span>
              <span>Giới hạn: {quiz.time_limit_minutes} phút</span>
            </>
          ) : null}
          {timeLeftSec != null && timeLeftSec > 0 && !result ? (
            <>
              <span>|</span>
              <span className="font-mono text-cyan-700">Còn lại: {fmtTime(timeLeftSec)}</span>
            </>
          ) : null}
        </div>
      </section>

      {error ? <p className="text-sm text-rose-600">{error}</p> : null}

      {result ? (
        <section className="space-y-6">
          <div className="rounded-2xl border border-emerald-100 bg-emerald-50 p-6">
            <h2 className="font-headline text-2xl font-bold text-emerald-800">Kết quả bài làm</h2>
            <p className="mt-2 text-emerald-700">
              Điểm: <strong>{result.score}%</strong> ({result.correct_answers}/{result.total_questions} câu đúng)
            </p>
            <p className="mt-1 text-sm text-emerald-700">
              Trạng thái: {result.passed ? 'Đạt' : 'Chưa đạt'} (mốc {result.pass_score}%)
            </p>
          </div>

          <div className="space-y-4">
            <h3 className="font-headline text-xl font-bold text-slate-800">Chi tiết từng câu</h3>
            {qr.map((row) => (
              <article
                key={row.question_id}
                className={`rounded-2xl border p-4 shadow-sm ${
                  row.is_correct ? 'border-emerald-200 bg-emerald-50/50' : 'border-rose-200 bg-rose-50/40'
                }`}
              >
                <p className="text-xs font-semibold text-slate-500">
                  Câu {row.question_order}
                  {row.is_correct ? (
                    <span className="ml-2 text-emerald-600">Đúng</span>
                  ) : (
                    <span className="ml-2 text-rose-600">Sai</span>
                  )}
                </p>
                <p className="mt-1 font-medium text-slate-800">{row.question_text}</p>
                <dl className="mt-3 space-y-1 text-sm">
                  <div className="flex flex-col gap-0.5 sm:flex-row sm:gap-2">
                    <dt className="text-slate-500">Bạn chọn:</dt>
                    <dd className="font-medium text-slate-800">{row.user_answer_display}</dd>
                  </div>
                  <div className="flex flex-col gap-0.5 sm:flex-row sm:gap-2">
                    <dt className="text-slate-500">Đáp án đúng:</dt>
                    <dd className="font-medium text-emerald-800">{row.correct_answer_display}</dd>
                  </div>
                </dl>
              </article>
            ))}
          </div>
        </section>
      ) : (
        <form
          onSubmit={(e) => {
            e.preventDefault();
            if (currentIndex >= total - 1) submit(e);
          }}
          className="space-y-4"
        >
          <div className="rounded-2xl bg-white p-4 shadow-sm">
            <label className="block text-sm font-semibold">Tên người làm bài (không bắt buộc)</label>
            <input
              value={playerName}
              onChange={(e) => setPlayerName(e.target.value)}
              className="mt-2 w-full rounded-xl border border-slate-200 px-3 py-2 text-sm"
              placeholder="Nhập tên hiển thị"
            />
          </div>

          {current ? (
            <article className="rounded-2xl bg-white p-6 shadow-sm">
              <div className="mb-4 flex items-center justify-between gap-2">
                <p className="text-sm font-semibold text-cyan-800">
                  Câu {currentIndex + 1} / {total}
                </p>
                <div className="h-2 flex-1 max-w-xs rounded-full bg-slate-100">
                  <div
                    className="h-2 rounded-full bg-cyan-600 transition-all"
                    style={{ width: `${((currentIndex + 1) / total) * 100}%` }}
                  />
                </div>
              </div>
              {current.image_url ? (
                <div className="mb-4 overflow-hidden rounded-xl border border-slate-100">
                  <img
                    src={current.image_url}
                    alt=""
                    className="max-h-64 w-full object-contain"
                  />
                </div>
              ) : null}
              <h3 className="text-lg font-semibold leading-snug text-slate-900">{current.question_text}</h3>
              {current.question_type === 'choice' ? (
                <div className="mt-4 space-y-2">
                  {(current.choices || []).map((choice, cIdx) => {
                    const value = String.fromCharCode(65 + cIdx);
                    return (
                      <label
                        key={`${current.id}-${value}`}
                        className="flex cursor-pointer items-start gap-3 rounded-xl border border-slate-100 p-3 transition hover:border-cyan-200 hover:bg-cyan-50/30"
                      >
                        <input
                          type="radio"
                          name={current.id}
                          value={value}
                          checked={answers[current.id] === value}
                          onChange={() => setAnswers((prev) => ({ ...prev, [current.id]: value }))}
                          className="mt-1"
                        />
                        <span className="text-sm leading-relaxed text-slate-800">
                          <strong className="text-cyan-800">{value}.</strong> {choice}
                        </span>
                      </label>
                    );
                  })}
                </div>
              ) : (
                <input
                  value={answers[current.id] || ''}
                  onChange={(e) => setAnswers((prev) => ({ ...prev, [current.id]: e.target.value }))}
                  className="mt-4 w-full rounded-xl border border-slate-200 px-3 py-2 text-sm"
                  placeholder="Nhập câu trả lời"
                />
              )}
              {current.hint ? <p className="mt-3 text-xs text-slate-500">Gợi ý: {current.hint}</p> : null}
            </article>
          ) : null}

          <div className="flex flex-wrap gap-3">
            <button
              type="button"
              disabled={currentIndex <= 0}
              onClick={() => setCurrentIndex((i) => Math.max(0, i - 1))}
              className="rounded-xl border border-slate-200 px-4 py-2 text-sm font-semibold text-slate-700 disabled:opacity-40"
            >
              ← Câu trước
            </button>
            {currentIndex < total - 1 ? (
              <button
                type="button"
                onClick={() => setCurrentIndex((i) => Math.min(total - 1, i + 1))}
                className="rounded-xl bg-cyan-700 px-4 py-2 text-sm font-bold text-white"
              >
                Câu tiếp →
              </button>
            ) : (
              <button
                type="submit"
                className="rounded-xl bg-emerald-700 px-4 py-2 text-sm font-bold text-white"
              >
                Nộp bài
              </button>
            )}
          </div>
        </form>
      )}
    </main>
  );
}
