import React from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useUserWorkspaceStore } from '@/presentation/workspace/useUserWorkspaceStore';
import { WorkspaceApiClient } from '@/infrastructure/workspace/WorkspaceApiClient';

function Sidebar({ appTitle, systemTagline, menuItems, roleLabel, onLogout, onOpenSupport }) {
  const navigate = useNavigate();
  const location = useLocation();
  return (
    <aside className="fixed left-0 top-0 z-40 hidden h-screen w-64 flex-col border-r border-slate-200 bg-slate-50 py-4 md:flex dark:border-slate-700 dark:bg-slate-900">
      <div className="mb-8 flex items-center gap-3 px-6 pt-2">
        <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-cyan-100">
          <span className="material-symbols-outlined text-cyan-600">school</span>
        </div>
        <div>
          <h2 className="font-headline text-lg font-extrabold text-cyan-700">{appTitle}</h2>
          <p className="text-[10px] uppercase tracking-wider text-slate-500">{systemTagline}</p>
        </div>
      </div>
      <nav className="flex-1 space-y-1">
        <button
          onClick={() => navigate('/dashboard')}
          className="mx-2 flex w-[calc(100%-1rem)] items-center gap-3 rounded-xl bg-cyan-50 px-6 py-3 text-left font-medium text-cyan-700"
        >
          <span className="material-symbols-outlined">dashboard</span>
          <span>Home</span>
        </button>
        {menuItems.map((item) => (
          <button
            key={item.id}
            onClick={() => {
              if (item.path) navigate(item.path);
            }}
            className={`mx-2 flex w-[calc(100%-1rem)] items-center gap-3 rounded-xl px-6 py-3 text-left font-medium transition ${
              item.path && location.pathname.startsWith(item.path)
                ? 'bg-cyan-50 text-cyan-700'
                : 'text-slate-600 hover:bg-slate-200/50 hover:text-cyan-600 dark:text-slate-300 dark:hover:bg-slate-800'
            }`}
          >
            <span className="material-symbols-outlined">{item.icon}</span>
            <span>{item.label}</span>
          </button>
        ))}
      </nav>
      <div className="mx-4 mt-auto border-t border-slate-200 pt-4 dark:border-slate-700">
        <div className="mb-3 rounded-lg bg-slate-100 px-3 py-2 text-xs font-semibold uppercase tracking-wide text-slate-600 dark:bg-slate-800 dark:text-slate-300">
          {roleLabel}
        </div>
        <button onClick={onOpenSupport} className="flex w-full items-center gap-3 rounded-lg px-4 py-2 text-sm text-slate-500 hover:text-cyan-600 dark:text-slate-300">
          <span className="material-symbols-outlined text-lg">help</span>
          Support
        </button>
        <button onClick={onLogout} className="flex w-full items-center gap-3 rounded-lg px-4 py-2 text-sm text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-950/30">
          <span className="material-symbols-outlined text-lg">logout</span>
          Log out
        </button>
      </div>
    </aside>
  );
}

function SupportModal({ open, setOpen, onSubmit }) {
  const [subject, setSubject] = React.useState('');
  const [message, setMessage] = React.useState('');
  const [result, setResult] = React.useState('');
  if (!open) return null;
  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center bg-slate-900/50 p-4">
      <div className="w-full max-w-lg rounded-2xl bg-white p-6 shadow-2xl dark:bg-slate-900">
        <div className="mb-3 flex items-center justify-between">
          <h3 className="font-headline text-xl font-bold dark:text-slate-100">Support Center</h3>
          <button onClick={() => setOpen(false)} className="rounded-full p-1 hover:bg-slate-100 dark:hover:bg-slate-800">
            <span className="material-symbols-outlined">close</span>
          </button>
        </div>
        <div className="mb-4 rounded-xl bg-sky-50 p-3 text-sm text-slate-700 dark:bg-slate-800 dark:text-slate-200">
          Liên hệ nhanh: <strong>support@quizatelier.app</strong> • Hotline: <strong>1900 1024</strong>
        </div>
        <div className="space-y-3">
          <input value={subject} onChange={(e) => setSubject(e.target.value)} placeholder="Tiêu đề ticket" className="w-full rounded-lg border border-slate-200 px-3 py-2 text-sm dark:border-slate-700 dark:bg-slate-800" />
          <textarea value={message} onChange={(e) => setMessage(e.target.value)} placeholder="Mô tả vấn đề cần hỗ trợ" className="h-32 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm dark:border-slate-700 dark:bg-slate-800" />
          <button
            onClick={async () => {
              try {
                const ticket = await onSubmit({
                category: 'support',
                subject: subject || 'General support request',
                message: message || 'No details',
                priority: 'normal',
              });
                setResult(`Đã tạo ticket ${ticket.id}`);
                setSubject('');
                setMessage('');
              } catch (e) {
                setResult(e.message || 'Tạo ticket thất bại.');
              }
            }}
            className="rounded-lg bg-cyan-600 px-4 py-2 text-sm font-bold text-white"
          >
            Gửi ticket cho Support Team
          </button>
          {result ? <p className="text-sm font-semibold text-emerald-700">{result}</p> : null}
        </div>
      </div>
    </div>
  );
}

function MiniPopover({ title, children, onOpenPage, buttonLabel }) {
  return (
    <div className="absolute right-0 top-12 z-50 w-80 rounded-2xl border border-slate-200 bg-white p-4 shadow-2xl dark:border-slate-700 dark:bg-slate-900">
      <div className="mb-3 flex items-center justify-between">
        <h4 className="font-headline text-lg font-bold dark:text-slate-100">{title}</h4>
        {onOpenPage ? (
          <button onClick={onOpenPage} className="text-sm font-bold text-cyan-600 hover:underline">
            Mở rộng
          </button>
        ) : null}
      </div>
      {children}
      {onOpenPage ? (
        <button onClick={onOpenPage} className="mt-4 w-full rounded-lg bg-cyan-600 px-3 py-2 text-sm font-bold text-white">
          {buttonLabel}
        </button>
      ) : null}
    </div>
  );
}

function Topbar({ profile, notifications, theme, onOpenAccountPage, onOpenSettingsPage, onOpenNotificationsPage, onOpenSupport }) {
  const [open, setOpen] = React.useState('');
  const unread = notifications.filter((n) => !n.read).length;

  return (
    <header className="fixed top-0 z-30 flex h-16 w-full items-center justify-between border-b border-slate-100 bg-white/80 px-6 backdrop-blur dark:border-slate-700 dark:bg-slate-900/80 md:left-64 md:w-[calc(100%-16rem)]">
      <div className="hidden items-center rounded-full bg-slate-100 px-4 py-2 md:flex dark:bg-slate-800">
        <span className="material-symbols-outlined mr-2 text-slate-500">search</span>
        <input className="w-72 border-none bg-transparent text-sm outline-none placeholder:text-slate-400 dark:text-slate-100" placeholder="Tìm kiếm..." type="text" />
      </div>
      <div className="relative ml-auto flex items-center gap-3">
        <button onClick={() => setOpen(open === 'noti' ? '' : 'noti')} className="relative rounded-full p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800">
          <span className="material-symbols-outlined">notifications</span>
          {unread > 0 ? <span className="absolute right-2 top-2 h-2 w-2 rounded-full bg-rose-500" /> : null}
        </button>
        {open === 'noti' ? (
          <MiniPopover title="Notifications" onOpenPage={onOpenNotificationsPage} buttonLabel="Mở trang notification">
            <div className="space-y-2 text-sm">
              {notifications.slice(0, 3).map((n) => (
                <div key={n.id} className="rounded-xl border border-slate-100 bg-slate-50 p-3 dark:border-slate-700 dark:bg-slate-800">
                  <p className="font-semibold">{n.title}</p>
                  <p className="mt-1">{n.message}</p>
                </div>
              ))}
              {notifications.length === 0 ? <p className="text-slate-500">Không có thông báo.</p> : null}
            </div>
          </MiniPopover>
        ) : null}

        <button onClick={() => setOpen(open === 'settings' ? '' : 'settings')} className="rounded-full p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800">
          <span className="material-symbols-outlined">settings</span>
        </button>
        {open === 'settings' ? (
          <MiniPopover title="Settings" onOpenPage={onOpenSettingsPage} buttonLabel="Mở trang settings">
            <p className="text-sm text-slate-600 dark:text-slate-300">Theme hiện tại: <strong>{theme}</strong></p>
          </MiniPopover>
        ) : null}

        <button onClick={() => setOpen(open === 'account' ? '' : 'account')} className="flex items-center gap-2 rounded-full border border-slate-200 bg-white px-3 py-1.5 dark:border-slate-700 dark:bg-slate-800">
          <div className="h-7 w-7 rounded-full bg-cyan-100" />
          <span className="text-sm font-semibold text-slate-700 dark:text-slate-100">{profile?.name || 'Tài khoản'}</span>
        </button>
        {open === 'account' ? (
          <MiniPopover title="Tài khoản" onOpenPage={onOpenAccountPage} buttonLabel="Mở trang quản lý tài khoản">
            <div className="space-y-1 text-sm">
              <p><strong>Tên:</strong> {profile?.name || 'N/A'}</p>
              <p><strong>Email:</strong> {profile?.email || 'N/A'}</p>
            </div>
          </MiniPopover>
        ) : null}

        <button onClick={onOpenSupport} className="rounded-full bg-cyan-600 p-2 text-white shadow-lg md:hidden">
          <span className="material-symbols-outlined">support_agent</span>
        </button>
      </div>
    </header>
  );
}

export default function RoleDashboardShell({ session, appTitle, systemTagline, roleLabel, menuItems, onLogout, children }) {
  const theme = useUserWorkspaceStore((s) => s.theme);
  const setTheme = useUserWorkspaceStore((s) => s.setTheme);
  const api = React.useMemo(() => new WorkspaceApiClient(), []);
  const token = session?.accessToken || null;
  const [profile, setProfile] = React.useState({
    name: session?.user?.name || 'Tài khoản',
    email: session?.user?.email || '',
  });
  const [notifications, setNotifications] = React.useState([]);
  const [supportOpen, setSupportOpen] = React.useState(false);
  const navigate = useNavigate();

  const loadSummary = React.useCallback(async () => {
    if (!token) return;
    try {
      const [account, noti, settings] = await Promise.all([
        api.getAccount(token),
        api.getNotifications(token),
        api.getSettings(token),
      ]);
      setProfile({
        name: account?.name || session?.user?.name || 'Tài khoản',
        email: account?.email || session?.user?.email || '',
      });
      setNotifications(noti?.items || []);
      if (settings?.theme === 'dark' || settings?.theme === 'light') {
        setTheme(settings.theme);
      }
    } catch {
      // keep graceful fallback for preview mode
    }
  }, [api, token, session?.user?.name, session?.user?.email, setTheme]);

  React.useEffect(() => {
    loadSummary();
  }, [loadSummary]);

  return (
    <div className="min-h-screen bg-sky-50 text-slate-900 dark:bg-slate-950 dark:text-slate-100">
      <Sidebar appTitle={appTitle} systemTagline={systemTagline} menuItems={menuItems} roleLabel={roleLabel} onLogout={onLogout} onOpenSupport={() => setSupportOpen(true)} />
      <Topbar
        profile={profile}
        notifications={notifications}
        theme={theme}
        onOpenAccountPage={() => navigate('/account')}
        onOpenSettingsPage={() => navigate('/settings')}
        onOpenNotificationsPage={() => navigate('/notifications')}
        onOpenSupport={() => setSupportOpen(true)}
      />
      <main className="px-4 pb-10 pt-20 md:ml-64 md:px-8">{children}</main>
      <SupportModal
        open={supportOpen}
        setOpen={setSupportOpen}
        onSubmit={async (payload) => {
          if (!token) return { id: 'LOCAL' };
          return api.createSupportTicket(payload, token);
        }}
      />
    </div>
  );
}

